/* Normalizador Bruto DL Soluções */

const item = $input.first().json.body || $input.first().json;

// 1. Limpeza de formatação de telefone (remove parênteses, traços e espaços)
let rawPhone = item.telefone || item.sender?.phone || "";
let cleanPhone = rawPhone.replace(/\D/g, ""); // Deixa apenas os números

// 2. Padronização do nome do Condomínio / Contato (Trim e Title Case simpificado)
let rawName = item.nome_condominio || item.nome_contato || item.sender?.name || "";
let cleanName = rawName.replace(/\s+/g, " ").trim();

// 3. Geração de UUID Simplificado e Carimbo de Data/Hora (Timestamp)
function generateUUID() { 
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) { 
        var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8); 
        return v.toString(16); 
    }); 
}

let lead_id = generateUUID();
let created_at = new Date().toISOString();

// 4. Payload Limpo e Final pronto para a ANINHA
return {
  json: {
    lead_id: lead_id,
    telefone_limpo: cleanPhone,
    nome_padronizado: cleanName,
    mensagem_original: item.mensagem || item.message?.content || "",
    origem_limpa: (item.source || item.origem || "organico").toLowerCase().trim(),
    created_at: created_at
  }
};
